vector<vector<int>> diagonalSort(vector<vector<int>>& mat) {
    int row = mat.size(), col = mat[0].size();
    map<int, priority_queue<int, vector<int>, greater<int>>> d;
    for(int i = 0; i < row; i++){
        for(int j = 0; j < col; j++){
            d[i - j].push(mat[i][j]);
        }
