const readline = require('readline');

const rl = readline.createInterface({
  input: process.stdin,
  output: process.stdout
});

let input = [];
rl.on('line', (line) => {
  input.push(line.trim());
});

rl.on('close', () => {
  const [n, m] = input[0].split(' ').map(Number);

  let mat = [];
  for (let i = 1; i <= n; i++) {
    mat.push(input[i].split(' ').map(Number));
  }

  function diagonalSort(mat) {
    const diagonals = {};

    // Collect elements along each diagonal
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < m; j++) {
        if (!diagonals[i - j]) diagonals[i - j] = [];
        diagonals[i - j].push(mat[i][j]);
      }
    }

    // Sort each diagonal
    for (const key in diagonals) {
      diagonals[key].sort((a, b) => a - b);
    }

    // Place sorted elements back into the matrix
    for (let i = 0; i < n; i++) {
      for (let j = 0; j < m; j++) {
        mat[i][j] = diagonals[i - j].shift();
      }
    }

    return mat;
  }

  mat = diagonalSort(mat);

  // Output the sorted matrix
  mat.forEach(row => console.log(row.join(' ')));
});
